set -euo pipefail

SOURCE_ROOT='/CHANGE/ME/source'
JELLYFIN_ROOT='/CHANGE/ME/jellyfin'

link_file() {
  local source=$1 destination=$2
  mkdir -p -- "$(dirname -- "$destination")"
  if [[ -e "$destination" ]]; then
    [[ "$source" -ef "$destination" ]] || { echo "Conflict: $destination" >&2; return 1; }
    return
  fi
  ln -- "$source" "$destination"
}

